from __future__ import annotations

import re

_FILENAME_PART_RE = re.compile(r"[^a-z0-9]+")


def _filename_part(text: str) -> str:
    return _FILENAME_PART_RE.sub("_", (text or "").strip().lower()).strip("_")


def application_pdf_filename(full_name: str, company_name: str) -> str:
    parts = [part for part in (full_name or "").strip().split() if part]
    if len(parts) >= 2:
        name_bits = [_filename_part(parts[0]), _filename_part(parts[-1])]
    elif len(parts) == 1:
        name_bits = [_filename_part(parts[0])]
    else:
        name_bits = ["resume"]

    company = _filename_part(company_name) or "company"
    return f"{'_'.join([*name_bits, company])}.pdf"

from relocation_jobs.mcp.names import application_pdf_filename


def test_application_pdf_filename_uses_first_and_last_name():
    assert application_pdf_filename("Jane Marie Doe", "Acme Backend Ltd") == (
        "jane_doe_acme_backend_ltd.pdf"
    )


def test_application_pdf_filename_single_name():
    assert application_pdf_filename("Madonna", "Google") == "madonna_google.pdf"


def test_application_pdf_filename_empty_name_falls_back_to_resume():
    assert application_pdf_filename("", "Stripe Inc") == "resume_stripe_inc.pdf"

